import { NotificationProps } from '../helpers/notification.helpers';

const NotificationContext = createContext(null);

const useNotification = () => {
  const [notificationElem, setNotificationElem] = useState<HTMLElement | null>(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElem(element);
    }
  }, []);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    try {
      const { heading, subheading, type } = props;
      await notificationElem.open({
        heading,
        subheading,
        type,
      });
    } catch (error) {
      setError(error);
    }
  };

  return { notificationElem, notify, error };
};

export default useNotification;
